use hal::TimeVal;
use log::debug;
use signal::SignalFlags;

use crate::tasks::{current_user_task, UserTaskControlFlow};

use super::UserTaskContainer;

impl UserTaskContainer {
    pub fn check_thread_exit(&self) -> Option<usize> {
        self.task
            .exit_code()
            .or(self.task.tcb.read().thread_exit_code.map(|x| x as usize))
    }

    pub fn check_timer(&self) {
        let mut pcb = self.task.pcb.lock();
        let timer = &mut pcb.timer[0];
        if timer.next > timer.last {
            let now = TimeVal::now();
            if now >= timer.next {
                self.task
                    .tcb
                    .write()
                    .signal
                    .add_signal(SignalFlags::SIGALRM);
                timer.last = timer.next;
            }
        }
    }

    pub async fn check_signal(&self) {
        loop {
            let sig_mask = self.task.tcb.read().sigmask;
            let signal = self
                .task
                .tcb
                .read()
                .signal
                .clone()
                .mask(sig_mask)
                .try_get_signal();
            if let Some(signal) = signal {
                debug!("mask: {:?}", sig_mask);
                self.handle_signal(signal.clone()).await;
                let mut tcb = self.task.tcb.write();
                tcb.signal.remove_signal(signal.clone());
                // check if it is a real time signal
                if let Some(index) = signal.real_time_index()
                    && tcb.signal_queue[index] > 0
                {
                    tcb.signal.add_signal(signal.clone());
                    tcb.signal_queue[index] -= 1;
                }
            } else {
                break;
            }
        }
    }

    pub async fn entry_point(&mut self, cx_ref: &mut TrapFrame) {
        let mut times: i32 = 0;

        loop {
            self.check_timer();

            self.check_signal().await;

            // check for task exit status.
            if let Some(exit_code) = self.check_thread_exit() {
                debug!(
                    "program exit with code: {}  task_id: {}  with  inner",
                    exit_code,
                    self.task.get_task_id()
                );
                break;
            }

            let res = future::or(self.handle_syscall(cx_ref), async {
                loop {
                    self.check_signal().await;

                    if let Some(_exit_code) = self.check_thread_exit() {
                        return UserTaskControlFlow::Break;
                    }
                    self.check_timer();
                    yield_now().await;
                }
            });

            if let UserTaskControlFlow::Break = res.await {
                break;
            }

            if let Some(exit_code) = self.check_thread_exit() {
                debug!(
                    "program exit with code: {}  task_id: {}  with  inner",
                    exit_code,
                    self.task.get_task_id()
                );
                break;
            }

            times += 1;
            if times >= 50 {
                times = 0;
                yield_now().await;
            }
        }

        debug!("exit_task: {}", self.task.get_task_id());
        kernel_page_table().change();
    }
}

#[async_recursion(Sync)]
pub async fn user_entry() {
    let task = current_user_task();
    let cx_ref = task.force_cx_ref();
    let tid = task.get_task_id();
    UserTaskContainer { task, tid }.entry_point(cx_ref).await;
}

use core::mem::size_of;

use polyhal::{TrapFrameArgs, SIG_RETURN_ADDR};
use executor::AsyncTask;
use log::debug;
use signal::SignalFlags;

use crate::syscall::consts::{SignalUserContext, UserRef};
use crate::tasks::{current_user_task, UserTaskControlFlow};

use super::UserTaskContainer;

impl UserTaskContainer {
    pub async fn handle_signal(&self, signal: SignalFlags) {
        debug!(
            "handle signal: {:?} task_id: {}",
            signal,
            self.task.get_task_id()
        );

        // if the signal is SIGKILL, then exit the task immediately.
        // the SIGKILL can't be catched and be ignored.
        if signal == SignalFlags::SIGKILL {
            self.task.exit_with_signal(signal.num());
        }

        // get the signal action for the signal.
        let sigaction = self.task.pcb.lock().sigaction[signal.num()].clone();

        // if there doesn't have signal handler.
        // Then use default handler. Exit or do nothing.
        // SIG_ERR = -1, SIG_DEF(default) = 0, SIG_IGN = 1(ignore)
        if sigaction.handler == 0 {
            match signal {
                SignalFlags::SIGCANCEL | SignalFlags::SIGSEGV | SignalFlags::SIGILL => {
                    current_user_task().exit_with_signal(signal.num());
                }
                _ => {}
            }
            return;
        }
        // ignore signal if the handler of is SIG_IGN(1)
        if sigaction.handler == 1 {
            return;
        }

        info!(
            "handle signal: {:?} task: {}",
            signal,
            self.task.get_task_id()
        );

        // let cx_ref = unsafe { task.get_cx_ptr().as_mut().unwrap() };
        let cx_ref = self.task.force_cx_ref();
        // store task_mask and context.
        let task_mask = self.task.tcb.read().sigmask;
        let store_cx = cx_ref.clone();
        self.task.tcb.write().sigmask = sigaction.mask;

        // alloc space for SignalUserContext at stack and align with 16 bytes.
        let sp = (cx_ref[TrapFrameArgs::SP] - 128 - size_of::<SignalUserContext>()) / 16 * 16;
        let cx: &mut SignalUserContext = UserRef::<SignalUserContext>::from(sp).get_mut();
        // change task context to do the signal.
        let mut tcb = self.task.tcb.write();
        cx.store_ctx(&cx_ref);
        cx.set_pc(tcb.cx[TrapFrameArgs::SEPC]);
        cx.sig_mask = sigaction.mask;
        tcb.cx[TrapFrameArgs::SP] = sp;
        tcb.cx[TrapFrameArgs::SEPC] = sigaction.handler;
        tcb.cx[TrapFrameArgs::RA] = if sigaction.restorer == 0 {
            SIG_RETURN_ADDR
        } else {
            sigaction.restorer
        };
        tcb.cx[TrapFrameArgs::ARG0] = signal.num();
        tcb.cx[TrapFrameArgs::ARG1] = 0;
        tcb.cx[TrapFrameArgs::ARG2] = cx as *mut SignalUserContext as usize;
        drop(tcb);

        loop {
            if let Some(exit_code) = self.task.exit_code() {
                debug!(
                    "program exit with code: {}  task_id: {}",
                    exit_code,
                    self.task.get_task_id()
                );
                break;
            }

            let cx_ref = self.task.force_cx_ref();

            debug!(
                "[task {}]task sepc: {:#x}",
                self.task.get_task_id(),
                cx_ref[TrapFrameArgs::SEPC]
            );

            if let UserTaskControlFlow::Break = self.handle_syscall(cx_ref).await {
                break;
            }
        }
        info!(
            "handle signal: {:?} task: {} ended",
            signal,
            self.task.get_task_id()
        );
        // restore sigmask to the mask before doing the signal.
        self.task.tcb.write().sigmask = task_mask;
        *cx_ref = store_cx;
        // copy pc from new_pc
        cx_ref[TrapFrameArgs::SEPC] = cx.pc();
        cx.restore_ctx(cx_ref);
    }
}

use core::cmp;

use alloc::{collections::VecDeque, sync::Arc};
use sync::Mutex;
use vfscore::{INodeInterface, PollEvent, VfsResult};

pub struct SocketPair {
    inner: Arc<Mutex<VecDeque<u8>>>,
}

impl INodeInterface for SocketPair {
    fn writeat(&self, _offset: usize, buffer: &[u8]) -> VfsResult<usize> {
        let mut queue = self.inner.lock();
        if queue.len() > 0x50000 {
            Err(vfscore::VfsError::Blocking)
        } else {
            let wlen = buffer.len();
            queue.extend(buffer.iter());
            Ok(wlen)
        }
    }

    fn readat(&self, _offset: usize, buffer: &mut [u8]) -> VfsResult<usize> {
        let mut queue = self.inner.lock();
        let rlen = cmp::min(queue.len(), buffer.len());
        queue
            .drain(..rlen)
            .enumerate()
            .into_iter()
            .for_each(|(i, x)| {
                buffer[i] = x;
            });
        if rlen == 0 {
            Err(vfscore::VfsError::Blocking)
        } else {
            Ok(rlen)
        }
    }

    fn poll(&self, events: PollEvent) -> VfsResult<PollEvent> {
        let mut res = PollEvent::NONE;
        if events.contains(PollEvent::POLLOUT) {
            if self.inner.lock().len() <= 0x50000 {
                res |= PollEvent::POLLOUT;
            }
        }
        if events.contains(PollEvent::POLLIN) {
            if self.inner.lock().len() > 0 {
                res |= PollEvent::POLLIN;
            }
        }
        Ok(res)
    }
}

pub fn create_socket_pair() -> Arc<SocketPair> {
    Arc::new(SocketPair {
        inner: Arc::new(Mutex::new(VecDeque::new())),
    })
}

